<template>
  <div class="emap" :class="{ 'emap-compact': compact, 'emap-fit-stage': fitStage }" ref="wrap">
    <div v-if="showControls || showViewToggle" class="emap-controls">
      <form v-if="showControls" class="emap-form index-ignore" @submit.prevent="runQuery">
        <input
          v-model="query"
          class="emap-input"
          type="text"
          autocomplete="off"
          spellcheck="false"
          placeholder="Drop a question into the map"
          aria-label="Query to place on the embedding map"
        >
        <button type="submit" class="emap-go" :disabled="busy">{{ busy ? '…' : 'Place' }}</button>
      </form>
      <div v-if="showControls" class="emap-samples index-ignore">
        <button v-for="s in samples" :key="s" type="button" class="emap-chip" :disabled="busy" @click="query = s; runQuery();">{{ s }}</button>
      </div>
      <div v-if="showViewToggle" class="emap-view-toggle index-ignore" aria-label="Map projection">
        <button
          type="button"
          class="emap-view"
          :class="{ active: viewMode === '2d' }"
          @click="setViewMode('2d')"
        >2D</button>
        <button
          type="button"
          class="emap-view"
          :class="{ active: viewMode === '3d' }"
          @click="setViewMode('3d')"
        >3D</button>
      </div>
    </div>
    <div class="emap-stage">
      <canvas ref="canvas" class="emap-canvas" aria-label="Map of every content chunk on this site, laid out by meaning"></canvas>
      <button
        v-if="tooltip"
        type="button"
        class="emap-tooltip"
        :style="{ left: tooltip.x + 'px', top: tooltip.y + 'px' }"
        @click.stop="goTo(tooltip.point)"
      >
        <span class="emap-tooltip-group">{{ tooltip.group }}</span>
        <span class="emap-tooltip-title">{{ tooltip.title }}</span>
      </button>
      <p v-if="status" class="emap-status">{{ status }}</p>
    </div>
    <div v-if="active && showHits" class="emap-hits index-ignore">
      <p class="emap-hits-label">Nearest passages to “{{ active.label }}”</p>
      <ol>
        <li v-for="h in active.list" :key="h.id">
          <button type="button" @click="goTo(h)">{{ h.title }}</button>
          <span class="emap-hit-score">{{ h.score.toFixed(2) }}</span>
        </li>
      </ol>
    </div>
    <p v-if="showCaption" class="emap-caption">
      Every dot is one indexed passage of this site, embedded into 384 dimensions and flattened to two
      or three dimensions with UMAP. Passages that talk about similar things sit close together, whatever
      page they live on. Scroll to zoom, drag to pan, click a dot to read the passage it stands for.
    </p>
  </div>
</template>

<script>
import * as d3 from 'd3';
import { ensureReady, semanticTopK } from '../utils/semanticSearch';

// Broad content families; finer than this and the map stops reading at a glance.
const GROUPS = [
  { key: 'profile', label: 'Profile', match: ['/about', '/education', '/experience', '/cv'] },
  { key: 'research', label: 'Research', match: ['/research'] },
  { key: 'projects', label: 'Projects', match: ['/projects', '/playbook', '/lexaday', '/dealtracker', '/scrollytelling', '/early', '/searchstory'] },
  { key: 'travels', label: 'Travels', match: ['/travels'] },
  { key: 'fragments', label: 'Fragments', match: ['/fragments'] },
];

const LIGHT = {
  profile: '#8d8d8d',
  research: '#7b6f9e',
  projects: '#6f8f86',
  travels: '#9a7f62',
  fragments: '#a87786',
  label: '#757575',
  star: '#b3893d',
  edge: '#b3893d',
};

const DARK = {
  profile: '#9a9a9a',
  research: '#a89ccf',
  projects: '#8faea5',
  travels: '#c4a482',
  fragments: '#c795a6',
  label: '#a1a1a1',
  star: '#d9b36a',
  edge: '#d9b36a',
};

function groupOf(route) {
  for (const g of GROUPS) if (g.match.includes(route)) return g.key;
  return 'profile';
}

export default {
  name: 'EmbeddingMap',
  props: {
    compact: {
      type: Boolean,
      default: false,
    },
    showControls: {
      type: Boolean,
      default: true,
    },
    showCaption: {
      type: Boolean,
      default: true,
    },
    showHits: {
      type: Boolean,
      default: true,
    },
    fitStage: {
      type: Boolean,
      default: false,
    },
    showViewToggle: {
      type: Boolean,
      default: true,
    },
    initialViewMode: {
      type: String,
      default: '2d',
    },
    allowNavigation: {
      type: Boolean,
      default: true,
    },
    allowZoom: {
      type: Boolean,
      default: true,
    },
  },
  emits: ['navigate', 'ready'],
  data() {
    return {
      query: '',
      busy: false,
      status: '',
      tooltip: null,
      active: null,
      viewMode: '2d',
      samples: ['exchange in Melbourne', 'what does Henry research?', 'growing up in Shanghai'],
    };
  },
  mounted() {
    this._points = [];
    this._transform = d3.zoomIdentity;
    this._introStart = 0;
    this._raf = null;
    this._spinRaf = null;
    this._focusRaf = null;
    this._hover = null;
    this._yaw = -0.72;
    this._pitch = 0.54;
    this._spinTime = 0;
    this._lastSpinTs = 0;
    this._keepActiveCentered = false;
    this.viewMode = this.initialViewMode === '3d' ? '3d' : '2d';

    this.loadPoints();

    this._onResize = () => this.scheduleResize();
    window.addEventListener('resize', this._onResize, { passive: true });

    this._themeObs = new MutationObserver(() => this.draw());
    this._themeObs.observe(document.body, { attributes: true, attributeFilter: ['class'] });
  },
  beforeUnmount() {
    if (this._raf) cancelAnimationFrame(this._raf);
    if (this._spinRaf) cancelAnimationFrame(this._spinRaf);
    if (this._focusRaf) cancelAnimationFrame(this._focusRaf);
    if (this._resizeRaf) cancelAnimationFrame(this._resizeRaf);
    if (this._onResize) window.removeEventListener('resize', this._onResize);
    if (this._themeObs) this._themeObs.disconnect();
  },
  methods: {
    palette() {
      return document.body.classList.contains('dark-mode') ? DARK : LIGHT;
    },
    async loadPoints() {
      try {
        const res = await fetch('/assets/embedding-map.json', { cache: 'no-cache' });
        if (!res.ok) throw new Error(`embedding-map.json ${res.status}`);
        const data = await res.json();
        this._points = data.items.map((p) => ({ ...p, group: groupOf(p.route) }));
        this._byId = null;
        this.$nextTick(() => {
          this.resize();
          this.startIntro();
          if (this.viewMode === '3d') this.start3dMotion();
          if (this._pendingExternalHits) {
            const pending = this._pendingExternalHits;
            this._pendingExternalHits = null;
            this.showExternalHits(pending.rawHits, pending.opts);
          }
          this.$emit('ready');
          setTimeout(() => this.resize(), 120);
        });
      } catch (e) {
        this.status = 'The map data failed to load.';
      }
    },
    scheduleResize() {
      if (this._resizeRaf) cancelAnimationFrame(this._resizeRaf);
      this._resizeRaf = requestAnimationFrame(() => {
        this._resizeRaf = null;
        this.resize();
      });
    },
    resize() {
      const wrap = this.$refs.wrap;
      const canvas = this.$refs.canvas;
      if (!wrap || !canvas) return;
      const w = wrap.clientWidth;
      if (!w) return;
      const h = this.fitStage ? this.fitHeight(w) : Math.max(340, Math.min(560, Math.round(w * 0.68)));
      const dpr = window.devicePixelRatio || 1;
      canvas.width = Math.round(w * dpr);
      canvas.height = Math.round(h * dpr);
      canvas.style.height = `${h}px`;
      this._w = w;
      this._h = h;
      this._dpr = dpr;
      this._lastObservedWidth = w;

      this.updateProjection();
      if (this.active) this.placeActive();

      if (this.allowZoom && !this._zoomBound) {
        this._zoomBound = true;
        this._zoom = d3.zoom()
          .scaleExtent([0.8, 9])
          .on('zoom', (ev) => { this._transform = ev.transform; this.tooltip = null; this.draw(); });
        d3.select(canvas).call(this._zoom);
      }
      if (!this._pointerBound) {
        this._pointerBound = true;
        d3.select(canvas)
          .on('mousemove.emapHover', (ev) => this.onMove(ev))
          .on('mouseleave.emapHover', () => { this._hover = null; this.tooltip = null; this.draw(); })
          .on('click.emapClick', (ev) => this.onClick(ev));
      }
      this.draw();
    },
    fitHeight(w) {
      const wrap = this.$refs.wrap;
      const controls = wrap && wrap.querySelector('.emap-controls');
      const controlsH = controls ? controls.getBoundingClientRect().height + 8 : 0;
      const h = Math.floor((wrap && wrap.clientHeight ? wrap.clientHeight : 0) - controlsH);
      if (h > 120) return Math.max(220, h);
      return Math.max(260, Math.min(420, Math.round(w * 0.62)));
    },
    updateProjection() {
      if (!this._points.length || !this._w || !this._h) return;
      for (const p of this._points) {
        if (this.viewMode === '3d' && typeof p.x3 === 'number') {
          const projected = this.project3d(p);
          p.px = projected.x;
          p.py = projected.y;
          p.depth = projected.depth;
        } else {
          p.px = p.x * this._w;
          p.py = p.y * this._h;
          p.depth = 0;
        }
      }
      this._tree = d3.quadtree().x((p) => p.px).y((p) => p.py).addAll(this._points);
      this._centroids = GROUPS.map((g) => {
        const pts = this._points.filter((p) => p.group === g.key);
        if (!pts.length) return null;
        return {
          key: g.key,
          label: g.label,
          px: d3.mean(pts, (p) => p.px),
          py: d3.mean(pts, (p) => p.py),
        };
      }).filter(Boolean);
    },
    project3d(p) {
      const x = ((p.x3 ?? p.x) - 0.5) * 2;
      const y = ((p.y3 ?? p.y) - 0.5) * 2;
      const z = ((p.z3 ?? 0.5) - 0.5) * 2;
      const yaw = this._yaw;
      const pitch = this._pitch;
      const cy = Math.cos(yaw), sy = Math.sin(yaw);
      const cp = Math.cos(pitch), sp = Math.sin(pitch);
      const x1 = x * cy + z * sy;
      const z1 = -x * sy + z * cy;
      const y1 = y * cp - z1 * sp;
      const z2 = y * sp + z1 * cp;
      const perspective = 1 / (1 + z2 * 0.35);
      return {
        x: this._w / 2 + x1 * perspective * this._w * 0.37,
        y: this._h / 2 + y1 * perspective * this._h * 0.43,
        depth: z2,
      };
    },
    setViewMode(mode) {
      if (this.viewMode === mode) return;
      this.viewMode = mode;
      this.tooltip = null;
      this.updateProjection();
      if (this.active) this.placeActive();
      this.draw();
      if (mode === '3d') this.start3dMotion();
      else this.stop3dMotion();
    },
    start3dMotion() {
      this.stop3dMotion();
      this._spinTime = 0;
      this._lastSpinTs = performance.now();
      if (window.matchMedia && window.matchMedia('(prefers-reduced-motion: reduce)').matches) return;
      const step = () => {
        if (this.viewMode !== '3d') return;
        const now = performance.now();
        if (!this._hover) this._spinTime += now - this._lastSpinTs;
        this._lastSpinTs = now;
        this._yaw = -0.72 + this._spinTime * 0.00016;
        this.updateProjection();
        if (this.active) this.placeActive();
        if (this._keepActiveCentered && this.active && !this._focusRaf) this.setActiveFocusTransform();
        this.draw();
        this._spinRaf = requestAnimationFrame(step);
      };
      this._spinRaf = requestAnimationFrame(step);
    },
    stop3dMotion() {
      if (this._spinRaf) cancelAnimationFrame(this._spinRaf);
      this._spinRaf = null;
      this._keepActiveCentered = false;
      this._yaw = -0.72;
      this._pitch = 0.54;
    },
    // The reveal derives from wall-clock time, not accumulated frames, so a
    // throttled or hidden tab can never leave the map stuck half-drawn.
    introProgress() {
      if (!this._introStart) return 1;
      if (window.matchMedia && window.matchMedia('(prefers-reduced-motion: reduce)').matches) return 1;
      return Math.min(1, (performance.now() - this._introStart) / 900);
    },
    startIntro() {
      this._introStart = performance.now();
      const step = () => {
        this.draw();
        if (this.introProgress() < 1) this._raf = requestAnimationFrame(step);
      };
      this._raf = requestAnimationFrame(step);
      this.draw();
      // rAF never fires in background tabs; make sure the settled frame paints.
      setTimeout(() => this.draw(), 1000);
    },
    pointAt(ev) {
      const [mx, my] = d3.pointer(ev, this.$refs.canvas);
      const [dx, dy] = this._transform.invert([mx, my]);
      const r = 12 / this._transform.k;
      const p = this._tree && this._tree.find(dx, dy, r);
      return p ? { p, mx, my } : null;
    },
    onMove(ev) {
      const hit = this.pointAt(ev);
      this._hover = hit ? hit.p : null;
      this.$refs.canvas.style.cursor = hit ? 'pointer' : 'grab';
      if (hit) {
        const g = GROUPS.find((x) => x.key === hit.p.group);
        this.tooltip = {
          x: Math.min(hit.mx + 14, this._w - 180),
          y: Math.max(hit.my - 12, 8),
          title: hit.p.title,
          group: g ? g.label : '',
          point: hit.p,
        };
      } else {
        this.tooltip = null;
      }
      this.draw();
    },
    onClick(ev) {
      if (!this.allowNavigation) return;
      const hit = this.pointAt(ev);
      if (!hit) return;
      if (window.matchMedia && window.matchMedia('(hover: none), (pointer: coarse)').matches) {
        this._hover = hit.p;
        const g = GROUPS.find((x) => x.key === hit.p.group);
        this.tooltip = {
          x: Math.min(hit.mx + 14, this._w - 180),
          y: Math.max(hit.my - 12, 8),
          title: hit.p.title,
          group: g ? g.label : '',
          point: hit.p,
        };
        this.draw();
        return;
      }
      this.goTo(hit.p);
    },
    goTo(p) {
      if (!this.allowNavigation) return;
      if (!p || !p.route) return;
      this.$emit('navigate', p);
      if (p.route === '/fragments' && p.anchor) {
        this.$router.push({ path: p.route, hash: `#${p.anchor}` }).catch(() => {});
        return;
      }
      this.$router.push({ path: p.route }).catch(() => {});
      const anchor = p.anchor;
      if (!anchor) return;
      let tries = 0;
      const jump = () => {
        const el = document.getElementById(anchor);
        if (el) el.scrollIntoView({ block: 'start' });
        else if (tries++ < 25) setTimeout(jump, 120);
      };
      this.$nextTick(jump);
    },
    async runQuery() {
      return this.placeQuery(this.query);
    },
    externalHits(rawHits) {
      const hits = [];
      for (const h of rawHits || []) {
        const id = h && h.id;
        const p = this.byId(id);
        if (!p) continue;
        hits.push({ id, score: typeof h.score === 'number' ? h.score : 0.8 });
      }
      return hits;
    },
    showExternalHits(rawHits, opts = {}) {
      if (!this._points.length) {
        this._pendingExternalHits = { rawHits, opts };
        return;
      }
      const hits = this.externalHits(rawHits);
      this._keepActiveCentered = !!opts.keepCentered;
      if (!hits.length) {
        this.active = null;
        this.tooltip = null;
        if (opts.zoomOut !== false) this.animateToFull(opts.duration || 700);
        else this.draw();
        return;
      }
      this.active = {
        label: opts.label || 'selected passages',
        hits,
        list: hits.slice(0, 5).map((h) => ({ ...this.byId(h.id), score: h.score })),
        born: performance.now(),
      };
      this.placeActive();
      if (opts.focus) this.animateToActive(opts.duration || 950);
      else if (opts.zoomOut !== false) this.animateToFull(opts.duration || 700);
      this.startPulse();
    },
    async placeQuery(rawQuery) {
      const q = String(rawQuery || '').trim();
      if (!q || this.busy || !this._points.length) return;
      this.query = q;
      this.busy = true;
      this.status = 'Warming up the on-device model (the first run downloads it to your browser)…';
      try {
        await ensureReady();
        this.status = '';
        const hits = (await semanticTopK(q, 8)).filter((h) => this.byId(h.id));
        if (!hits.length) { this.status = 'No passages found for that.'; return; }
        this.active = {
          label: q,
          hits,
          list: hits.slice(0, 5).map((h) => ({ ...this.byId(h.id), score: h.score })),
          born: performance.now(),
        };
        this.placeActive();
        this.startPulse();
      } catch (e) {
        this.status = 'The model could not load right now; the map itself still works.';
      } finally {
        this.busy = false;
      }
    },
    // Star position is the similarity-weighted centroid of the hits, in the
    // current pixel space; recomputed whenever the canvas is resized.
    placeActive() {
      if (!this.active) return;
      let wx = 0, wy = 0, wsum = 0;
      for (const h of this.active.hits) {
        const p = this.byId(h.id);
        if (!p) continue;
        const w = Math.max(h.score, 0.01);
        wx += p.px * w; wy += p.py * w; wsum += w;
      }
      if (wsum > 0) {
        this.active.x = wx / wsum;
        this.active.y = wy / wsum;
      }
    },
    activeFocusTransform() {
      if (!this.active || !this.active.hits.length || !this._w || !this._h) return d3.zoomIdentity;
      const pts = this.active.hits.map((h) => this.byId(h.id)).filter(Boolean);
      if (!pts.length) return d3.zoomIdentity;
      const xs = pts.map((p) => p.px);
      const ys = pts.map((p) => p.py);
      if (Number.isFinite(this.active.x) && Number.isFinite(this.active.y)) {
        xs.push(this.active.x);
        ys.push(this.active.y);
      }
      const minX = Math.min(...xs), maxX = Math.max(...xs);
      const minY = Math.min(...ys), maxY = Math.max(...ys);
      const boxW = Math.max(28, maxX - minX);
      const boxH = Math.max(28, maxY - minY);
      const pad = Math.min(86, Math.max(42, Math.min(this._w, this._h) * 0.18));
      const k = Math.max(1.7, Math.min(4.8, Math.min((this._w - pad * 2) / boxW, (this._h - pad * 2) / boxH)));
      const cx = (minX + maxX) / 2;
      const cy = (minY + maxY) / 2;
      return d3.zoomIdentity.translate(this._w / 2 - cx * k, this._h / 2 - cy * k).scale(k);
    },
    setActiveFocusTransform() {
      this._transform = this.activeFocusTransform();
    },
    animateToActive(duration = 900) {
      this.animateTransform(this.activeFocusTransform(), duration);
    },
    animateToFull(duration = 700) {
      this._keepActiveCentered = false;
      this.animateTransform(d3.zoomIdentity, duration);
    },
    animateTransform(to, duration = 700) {
      if (this._focusRaf) cancelAnimationFrame(this._focusRaf);
      const from = this._transform || d3.zoomIdentity;
      const start = performance.now();
      const ease = (x) => 1 - Math.pow(1 - x, 3);
      const step = () => {
        const t = Math.min(1, (performance.now() - start) / duration);
        const e = ease(t);
        this._transform = d3.zoomIdentity
          .translate(from.x + (to.x - from.x) * e, from.y + (to.y - from.y) * e)
          .scale(from.k + (to.k - from.k) * e);
        this.draw();
        if (t < 1) this._focusRaf = requestAnimationFrame(step);
        else this._focusRaf = null;
      };
      this._focusRaf = requestAnimationFrame(step);
    },
    byId(id) {
      if (!this._byId) {
        this._byId = {};
        for (const p of this._points) this._byId[p.id] = p;
      }
      return this._byId[id];
    },
    startPulse() {
      if (this._raf) cancelAnimationFrame(this._raf);
      if (window.matchMedia && window.matchMedia('(prefers-reduced-motion: reduce)').matches) {
        this.draw();
        return;
      }
      const step = () => {
        this.draw();
        if (this.active && performance.now() - this.active.born < 1600) {
          this._raf = requestAnimationFrame(step);
        }
      };
      this._raf = requestAnimationFrame(step);
      setTimeout(() => this.draw(), 1700);
    },
    draw() {
      const canvas = this.$refs.canvas;
      if (!canvas || !this._points.length) return;
      const ctx = canvas.getContext('2d');
      const pal = this.palette();
      const t = this._transform;
      const dpr = this._dpr || 1;

      ctx.save();
      ctx.setTransform(dpr, 0, 0, dpr, 0, 0);
      ctx.clearRect(0, 0, this._w, this._h);

      const ease = (x) => 1 - Math.pow(1 - x, 3);
      const intro = ease(this.introProgress());
      const r = 3.6 * Math.pow(t.k, 0.3);

      // Constellation edges from the query star to its nearest passages.
      if (this.active) {
        const age = (performance.now() - this.active.born) / 1600;
        const grow = ease(Math.min(1, age));
        const [sx, sy] = t.apply([this.active.x, this.active.y]);
        for (const h of this.active.hits) {
          const p = this.byId(h.id);
          if (!p) continue;
          const [hx, hy] = t.apply([p.px, p.py]);
          ctx.strokeStyle = pal.edge;
          ctx.globalAlpha = Math.max(0.1, h.score * 0.55) * grow;
          ctx.lineWidth = 1;
          ctx.beginPath();
          ctx.moveTo(sx, sy);
          ctx.lineTo(sx + (hx - sx) * grow, sy + (hy - sy) * grow);
          ctx.stroke();
        }
        ctx.globalAlpha = 1;
      }

      // Points.
      const activeIds = this.active ? new Set(this.active.hits.map((h) => h.id)) : null;
      const drawPoints = this.viewMode === '3d'
        ? [...this._points].sort((a, b) => a.depth - b.depth)
        : this._points;
      drawPoints.forEach((p, i) => {
        const [x, y] = t.apply([p.px, p.py]);
        if (x < -20 || y < -20 || x > this._w + 20 || y > this._h + 20) return;
        const stagger = Math.min(1, Math.max(0, intro * 1.35 - (i / this._points.length) * 0.35));
        const isHit = activeIds && activeIds.has(p.id);
        const isHover = this._hover === p;
        const depthAlpha = this.viewMode === '3d' ? Math.max(0.28, Math.min(1, 0.68 + p.depth * 0.28)) : 1;
        const depthSize = this.viewMode === '3d' ? Math.max(0.52, Math.min(1.5, 1 + p.depth * 0.24)) : 1;
        ctx.globalAlpha = (isHit || isHover ? 0.95 : 0.72) * stagger * depthAlpha;
        ctx.fillStyle = pal[p.group];
        ctx.beginPath();
        ctx.arc(x, y, (isHover ? r + 2 : (isHit ? r + 1 : r)) * depthSize, 0, Math.PI * 2);
        ctx.fill();
        if (isHit) {
          ctx.globalAlpha = 0.35 * stagger;
          ctx.strokeStyle = pal.edge;
          ctx.lineWidth = 1;
          ctx.beginPath();
          ctx.arc(x, y, r + 4, 0, Math.PI * 2);
          ctx.stroke();
